DROP TABLE IF EXISTS `borrow_transactions`;
CREATE TABLE `borrow_transactions` (
  `id` int NOT NULL AUTO_INCREMENT,
  `transaction_code` varchar(50) NOT NULL,
  `borrower_id` int NOT NULL,
  `requested_by` int DEFAULT NULL,
  `borrower_name` varchar(100) NOT NULL,
  `borrower_department` varchar(100) DEFAULT NULL,
  `borrower_department_id` int DEFAULT NULL,
  `purpose` text,
  `borrow_date` date NOT NULL,
  `expected_return_date` date DEFAULT NULL,
  `status` enum('Pending','Approved','Rejected','Borrowed','Returned','Overdue') DEFAULT 'Pending',
  `approved_by` int DEFAULT NULL,
  `approved_at` timestamp NULL DEFAULT NULL,
  `notes` text,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `transaction_code` (`transaction_code`),
  KEY `approved_by` (`approved_by`),
  KEY `idx_borrow_status` (`status`),
  KEY `idx_borrow_date` (`borrow_date`),
  KEY `idx_borrow_tx_borrower_status` (`borrower_id`,`status`),
  CONSTRAINT `borrow_transactions_ibfk_1` FOREIGN KEY (`borrower_id`) REFERENCES `users` (`id`) ON DELETE RESTRICT,
  CONSTRAINT `borrow_transactions_ibfk_2` FOREIGN KEY (`approved_by`) REFERENCES `users` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

INSERT INTO `borrow_transactions` (`id`, `transaction_code`, `borrower_id`, `requested_by`, `borrower_name`, `borrower_department`, `borrower_department_id`, `purpose`, `borrow_date`, `expected_return_date`, `status`, `approved_by`, `approved_at`, `notes`, `created_at`, `updated_at`) VALUES (1, 'BRW-20260713-4286', 1, 1, 'System Administrator', NULL, NULL, 'sdfg', '2026-07-13', NULL, 'Pending', NULL, NULL, NULL, '2026-07-13 15:16:11', '2026-07-13 15:16:11');

